var e=[{id:`L8_1`,type:`dialog`,speaker:`JIA_ALPHA_NULL_NULL`,text:{KOREA:`무척 커다란 전차네요. 메카닉스에 저런 게 있는 줄은 몰랐어요.`,JPN:`とても大きな戦車ですね。メカニックスにあんな物があるとは知りませんでした。`,ENG:`What a massive tank. I didn’t know Mechanics had such a thing.`,TWN:`好大的戰車，沒想到機械裡竟然有那種東西。`},stage:{bg:`HANGAR`,slots:{L:null,C:{char_id:`JIA_ALPHA_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L9_1`,type:`dialog`,speaker:`JIA_ALPHA_NULL_NULL`,text:{KOREA:`상혁 오라버니가 사들이신 걸까요? 어릴 때부터 커다란 기계를 좋아하셨으니까요.`,JPN:`タツヤお兄様が買い付けた物でしょうか？
子どもの頃から大きな機械が好きでしたから。`,ENG:`Did Sanghyuk buy this? He was also a fan of gigantic machinery since he was little.`,TWN:`是沈尚哥買的嗎？他從小就很喜歡大型的機械。`},stage:{bg:`HANGAR`,slots:{L:null,C:{char_id:`JIA_ALPHA_NULL_NULL`,face:`UNIT_PRIDE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`CECILIA_NPC_ALPHA_NULL`,text:{KOREA:`지아야! 그렇게 여유 부릴 때가 아니다!`,JPN:`ユイちゃん！　そんな余裕を見せてる時間はないわ！`,ENG:`Jia! Stop fooling around!`,TWN:`小佳！現在不是討論這個問題的時候啦！`},stage:{bg:`HANGAR`,slots:{L:null,C:{char_id:`CECILIA_NPC_ALPHA_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`CECILIA_NPC_ALPHA_NULL`,text:{KOREA:`아까부터 우리 쪽 공격은 하나도 안 통하지 않느냐!`,JPN:`さっきからこっちの攻撃が全然効いてないじゃない！`,ENG:`Our attacks aren’t even making a dent in that thing!`,TWN:`我們這邊的攻擊對他們來說根本就沒用嘛！`},stage:{bg:`HANGAR`,slots:{L:null,C:{char_id:`CECILIA_NPC_ALPHA_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`JIA_ALPHA_NULL_NULL`,text:{KOREA:`네. 그래서 이제 막 준비를 마친 참이에요.`,JPN:`はい。ちょうど今、準備が整いました。`,ENG:`Yes, I’m almost finished getting ready.`,TWN:`對，所以我才剛準備好而已。`},stage:{bg:`HANGAR`,slots:{L:null,C:{char_id:`JIA_ALPHA_NULL_NULL`,face:`UNIT_PRIDE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`CECILIA_NPC_ALPHA_NULL`,text:{KOREA:`응? 준비라니?`,JPN:`うん？　準備って？`,ENG:`Hmm? Getting ready?`,TWN:`嗯？準備什麼？`},stage:{bg:`HANGAR`,slots:{L:null,C:{char_id:`CECILIA_NPC_ALPHA_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L20_1`,type:`dialog`,speaker:`JIA_ALPHA_NULL_NULL`,text:{KOREA:`구동계의 취약점을 파악하려면 시간이 필요했거든요.`,JPN:`駆動システムの弱点の把握に時間がかかりました。`,ENG:`I needed time to find the drivetrain’s weak point.`,TWN:`掌握驅動器的弱點需要一些時間，`},stage:{bg:`HANGAR`,slots:{L:{char_id:`JIA_ALPHA_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:null}}},{id:`L21_1`,type:`dialog`,speaker:`JIA_ALPHA_NULL_NULL`,text:{KOREA:`꼭 부술 필요 없이 움직이지 못하게만 만들어도 충분하니까요.`,JPN:`別に壊さなくても、動けないようにするだけで十分でしょう。`,ENG:`It’s good enough to simply immobilize it without breaking it.`,TWN:`我不打算毀掉整台機械，只要讓它不能運作就好。`},stage:{bg:`HANGAR`,slots:{L:null,C:null,R:{char_id:`JIA_ALPHA_NULL_NULL`,face:`UNIT_LAUGH`}}}},{id:`L33_1`,type:`dialog`,speaker:`CECILIA_NPC_ALPHA_NULL`,text:{KOREA:`대, 대단하구나! 분신들만으로 저 커다란 쇳덩이를 꼼짝 못하게 만들다니!`,JPN:`す、すごいじゃない！　分身だけであのデカい鉄の塊を無力化するなんて！`,ENG:`A-amazing! You stopped that chunk of metal with only your clones!`,TWN:`好…好厲害！竟然光靠分身，就能夠讓那個巨大的鐵塊動彈不得！`},stage:{bg:`HANGAR`,slots:{L:{char_id:`JIA_ALPHA_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`CECILIA_NPC_ALPHA_NULL`,face:`UNIT_IDLE`}}}},{id:`L34_1`,type:`dialog`,speaker:`JIA_ALPHA_NULL_NULL`,text:{KOREA:`자, 이 틈에 어서 빠져 나가요.`,JPN:`さあ、この隙に早く逃げましょう。`,ENG:`We need to leave now.`,TWN:`我們趁現在逃走吧！`},stage:{bg:`HANGAR`,slots:{L:{char_id:`JIA_ALPHA_NULL_NULL`,face:`UNIT_PRIDE`},C:null,R:{char_id:`CECILIA_NPC_ALPHA_NULL`,face:`UNIT_IDLE`}}}},{id:`L36_1`,type:`dialog`,speaker:`GUARD_NPC_ALPHA_NULL`,text:{KOREA:`그냥 가시게 내버려 둘 수 없습니다, 아가씨!`,JPN:`そうはいきません、お嬢様！`,ENG:`I can’t let you leave, Miss!`,TWN:`小姐！恕我無法放行！`},stage:{bg:`HANGAR`,slots:{L:null,C:{char_id:`GUARD_NPC_ALPHA_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L39_1`,type:`dialog`,speaker:`GUARD_NPC_ALPHA_NULL`,text:{KOREA:`아가씨가 사람을 해칠 분이라고는 생각하지 않습니다.`,JPN:`お嬢様が人を傷つけるような方だとは思いません。`,ENG:`I know you aren’t the kind of person who harms others.`,TWN:`我不認為小姐是殺人兇手。`},stage:{bg:`HANGAR`,slots:{L:{char_id:`GUARD_EXTRA_NANA_B`,face:`UNIT_IDLE`},C:{char_id:`GUARD_NPC_ALPHA_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L40_1`,type:`dialog`,speaker:`GUARD_NPC_ALPHA_NULL`,text:{KOREA:`하지만 정말 결백하시다면 도망치실 필요도 없는 것 아닙니까?`,JPN:`ですが、本当に潔白ならば、逃げる必要もないのではありませんか？`,ENG:`But, if you truly were innocent, you wouldn’t have to run away!`,TWN:`但若小姐真是清白的，又何須要逃呢？`},stage:{bg:`HANGAR`,slots:{L:{char_id:`GUARD_EXTRA_NANA_B`,face:`UNIT_IDLE`},C:{char_id:`GUARD_NPC_ALPHA_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L41_1`,type:`dialog`,speaker:`GUARD_NPC_ALPHA_NULL`,text:{KOREA:`도망만 친다고 문제가 해결되진 않습니다. 이대로는 의심만 더 키울 뿐이에요.`,JPN:`逃げることで問題が解決できるわけではありません。
このままでは疑惑が増すだけです。`,ENG:`Running away doesn’t solve anything. It only makes things worse.`,TWN:`逃跑並不能解決問題，只會令人更加起疑而已。`},stage:{bg:`HANGAR`,slots:{L:{char_id:`GUARD_EXTRA_NANA_B`,face:`UNIT_IDLE`},C:{char_id:`GUARD_NPC_ALPHA_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};